import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

export const Schema = z.object({
  // --- 系统审计 (核心资源) ---
  系统审计: z.object({
    当前时间: z.string().prefault('修正纪元0年'),
    当前地点: z.string().prefault('未知节点'),
    当前修正场面: z.string().prefault('无'),

    // [核心] 算力: 生命与金钱的统称。归零即BAD END。
    当前算力: z.coerce.number().transform(v => _.clamp(v, 0, 9999)).prefault(1000),

    // [核心] 灾星: 桃花债/修罗场指数。越高越容易被柴刀。
    红鸾灾星: z.coerce.number().prefault(0),

    // [环境] 压力: 随着回合数增加，生存税会越来越高。
    系统压力: z.coerce.number().prefault(1),
  }),

  // --- 修正者背包 ---
  修正者: z.object({
    存读档次数: z.coerce.number().prefault(1),
    道具栏: z.record(
      z.string(),
      z.object({ 数量: z.coerce.number(), 描述: z.string() })
    ).prefault({}),
  }),

  // --- 异常个体档案 (原武将图鉴) ---
  异常个体: z.record(
    z.string().describe('武将姓名'),
    z.object({
      // [核心] 侵蚀度: 0-100。越高越病娇/鬼畜。
      侵蚀度: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),

      // 状态标签: 如 [发情] [逻辑死锁] [正常]
      状态标签: z.string().prefault('未观测'),

      // 已发现弱点
      已发现弱点: z.array(z.string()).prefault([]),

      // 是否攻略/臣服
      是否攻略: z.boolean().prefault(false),
    }).prefault({})
  ).prefault({}),
});

$(() => { registerMvuSchema(Schema); })

