<script>
(function(){
  try {
    // 1. 头像映射表
    const avatars = {
      '曹操': 'https://i.ibb.co/6ccq07xz/caocao1.png',
      '刘备': 'https://i.ibb.co/7NZ8LsN2/liubei.png',
      '关羽': 'https://i.ibb.co/3yM8XjpY/guanyu1.png',
      '张飞': 'https://i.ibb.co/v6qXKzds/zhangfei.png',
      '诸葛亮': 'https://i.ibb.co/qM07BgrF/kongming.png',
      '吕布': 'https://i.ibb.co/ycTgp3d5/lvbu.png',
      '周瑜': 'https://i.ibb.co/933QsLn8/zhouyu.png',
      '孙权': 'https://i.ibb.co/GGNzZkq/sunquan.png',
      '孙策': 'https://i.ibb.co/4nJ55jvG/sunce.png',
      '大乔': 'https://i.ibb.co/RTCLgK1k/daqiao.png',
      '小乔': 'https://i.ibb.co/99cyrryy/xiaoqiao.png',
      '孙尚香': 'https://i.ibb.co/Y4cfJpDJ/sunshangxiang.png',
      '华佗': 'https://i.ibb.co/b9mwd4k/huatuo.png',
      '董卓': 'https://i.ibb.co/HykgPzk/donzhuo.png',
      '袁绍': 'https://i.ibb.co/GQqmFWtj/yuanshao.png',
      '貂蝉': 'https://i.ibb.co/rfdvsfPc/diaochan.png',
      '蔡文姬': 'https://i.ibb.co/NhDVcYn/caiwenji.png',
      '糜夫人': 'https://i.ibb.co/9kwTC4f8/mifuren.png',
      '孙坚': 'https://i.ibb.co/1J0VGcFZ/sunjian.png',
      '袁术': 'https://i.ibb.co/HDFmvCM2/yuanshu.png',
      '赵云': 'https://i.ibb.co/27YHsLc5/zhaoyun.png',
      '郭嘉': 'https://i.ibb.co/JwL2PBwh/guojia.png',
      '荀彧': 'https://i.ibb.co/20Gj1ffX/xunyu.png',
      '司马懿': 'https://i.ibb.co/rGzxhmvM/simayi.png',
      '许褚': 'https://i.ibb.co/n8nVtMMk/xuchu.png',
      '张辽': 'https://i.ibb.co/sdqFDYBC/zhangliao.png'
    };
    const defaultAvatar = 'https://via.placeholder.com/36/222/555?text=?';

   // 2. 场景-角色映射表 (修复版)
    const rosterRules = [
      {
        // 选项A：董卓发飙
        // 修改：去掉了单字"酸"，改为"不怕酸"、"肉酸"
        keywords: ['董卓', '肉酸', '不怕酸', '朝堂', '选项A'],
        roles: ['董卓', '王允', '吕布', '貂蝉']
      },
      {
        // 选项B：曹操锐评孙坚 (酸枣大营)
        keywords: ['孙文台', '骄兵', '酸枣', '意料之中', '选项B'],
        roles: ['曹操', '袁绍', '袁术']
      },
      {
        // 选项C：曹操劝架 (酸枣大营)
        keywords: ['吃什么', '公路', '诸侯', '选项C'],
        roles: ['曹操', '袁绍', '袁术', '刘备', '关羽', '张飞']
      },
      {
        // 选项D：孙策喊娘 (洛阳废墟)
        keywords: ['孙坚', '玉玺', '长乐宫', '母慈子孝', '称帝', '选项D'],
        roles: ['孙坚', '孙策', '孙权', '周瑜']
      },
      {
        // 选项E：刘备尬诗 (丞相府)
        keywords: ['煮酒', '龙虎', '好风', '傲苍穹', '选项E'],
        roles: ['曹操', '刘备']
      },
      {
        // 选项F：曹操狂怒 (丞相府)
        keywords: ['徐州', '馒头', '八万', '无能狂怒', '选项F'],
        roles: ['曹操', '荀彧']
      },
      {
        // 选项G：刘备自刎 (长坂坡)
        keywords: ['长坂', '自刎', '追杀', '选项G'],
        roles: ['刘备', '赵云', '张飞', '曹操', '诸葛亮']
      }
    ];

    // 3. 获取MVU数据
    let allVars = {};
    if (typeof getAllVariables === 'function') {
      allVars = getAllVariables();
    } else {
      console.warn('getAllVariables not found.');
    }

    const getVar = (path, defaultVal) => {
      if (typeof _ !== 'undefined' && _.get) return _.get(allVars, path, defaultVal);
      return defaultVal;
    };

    const sysData = getVar('stat_data.系统审计', {});
    const userData = getVar('stat_data.修正者', {});
    const anomData = getVar('stat_data.异常个体', {});

    // 4. 填充数据
    // --- 概览 ---
    const currentScene = sysData.当前修正场面 || '无';
    document.getElementById('sys-loc').innerText = sysData.当前地点 || '未知节点';
    document.getElementById('sys-time').innerText = sysData.当前时间 || '修正纪元0年';
    document.getElementById('sys-scene').innerText = currentScene;

    // --- 核心数值 ---
    const power = parseInt(sysData.当前算力) || 0;
    const powerMax = 9999;
    const doom = parseInt(sysData.红鸾灾星) || 0;
    const stress = parseFloat(sysData.系统压力) || 1.0;

    document.getElementById('val-power').innerText = power;
    document.getElementById('bar-power').style.width = Math.min(100, (power / powerMax) * 100) + '%';
    document.getElementById('val-doom').innerText = doom;
    document.getElementById('bar-doom').style.width = Math.min(100, doom) + '%';
    document.getElementById('val-stress').innerText = stress.toFixed(2) + 'x';

    // --- 异常个体 (智能过滤) ---
    const listEl = document.getElementById('anom-list');
    let activeRoles = [];
    let matched = false;

    // 匹配算法：遍历规则，找到第一个匹配的规则
    for (let rule of rosterRules) {
      // 检查 currentScene 是否包含 keywords 中的任意一个
      const isMatch = rule.keywords.some(kw => currentScene.includes(kw));
      if (isMatch) {
        activeRoles = rule.roles;
        matched = true;
        break;
      }
    }

    // 【重要修正】只有当真正匹配不到任何场景时，才清空列表
    // 并且不再有"全显"保底，防止穿帮。
    // 如果没有匹配到，activeRoles 为空数组。

    if (listEl) {
      listEl.innerHTML = '';
      let hasDisplay = false;

      if (matched && activeRoles.length > 0) {
        Object.entries(anomData).forEach(([name, data]) => {
          // 只显示名单里的人
          if (activeRoles.includes(name)) {
            hasDisplay = true;
            const erosion = parseInt(data.侵蚀度) || 0;
            const status = data.状态标签 || '未观测';
            const imgUrl = avatars[name] || defaultAvatar;

            const html = `
            <div class="anom-card">
              <div class="anom-avatar"><img src="${imgUrl}" class="anom-img" onerror="this.src='${defaultAvatar}'"></div>
              <div class="anom-info">
                <div class="anom-top">
                  <span class="anom-name">${name}</span>
                  <span class="anom-state">${status}</span>
                </div>
                <div class="erosion-bar">
                  <div class="erosion-fill" style="width:${Math.min(100, erosion)}%"></div>
                  <span class="erosion-val">${erosion}%</span>
                </div>
              </div>
            </div>`;
            listEl.innerHTML += html;
          }
        });
      }

      if (!hasDisplay) {
        // 如果没有匹配到场景，或者名单里的人都没有数据
        const msg = matched ? '-- 目标个体数据丢失 --' : '-- 场景未收录，停止观测 --';
        listEl.innerHTML = `<div style="text-align:center; padding:10px; color:#444; font-size:10px;">${msg}</div>`;
      }
    }

    // --- 修正者背包 ---
    document.getElementById('val-save').innerText = userData.存读档次数 || 0;
    const items = userData.道具栏 || {};
    const dotsEl = document.getElementById('bag-dots');
    if (dotsEl) {
      dotsEl.innerHTML = '';
      const keys = Object.keys(items);
      for(let i=0; i<5; i++) {
        const hasItem = i < keys.length;
        const dot = document.createElement('div');
        dot.className = `item-dot ${hasItem ? 'has' : ''}`;
        dotsEl.appendChild(dot);
      }
    }

  } catch (err) {
    console.error('Audit UI Error:', err);
    const errEl = document.getElementById('error-display');
    if (errEl) {
      errEl.style.display = 'block';
      errEl.innerText = 'ERR: ' + err.message;
    }
  }
})();
</script>

</body>
</html>
